from flask import Flask, request, jsonify
import os
from werkzeug.utils import secure_filename
from PIL import Image
from io import BytesIO
import zipfile
import mimetypes

app = Flask(__name__)

# Allowed file types
ALLOWED_EXTENSIONS = {'jpg', 'jpeg', 'png', 'gif', 'bmp'}

# Storage path
UPLOAD_FOLDER = '/path/to/uploads'
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

@app.route('/upload', methods=['POST'])
def upload():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    file = request.files['file']
    
    # Check if the file is allowed
    if not allowed_file(file.filename):
        return jsonify({'error': 'File type not allowed'}), 400
    
    # Get the file extension and MIME type
    filename, file_extension = os.path.splitext(file.filename)
    mime_type = mimetypes.guess_type(file.filename)[0]
    
    # Validate the file content (e.g., check for malicious code)
    if mime_type == 'application/zip':
        try:
            with zipfile.ZipFile(BytesIO(file.read())) as zip_ref:
                for f in zip_ref.namelist():
                    if not allowed_file(f):
                        return jsonify({'error': 'Invalid file type'}), 400
        except Exception as e:
            return jsonify({'error': str(e)}), 400
    
    # Generate a server-side filename and store the upload outside public paths
    filename = secure_filename(file.filename)
    file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    
    # Apply size limits (e.g., 5MB)
    if file.content_length > 5 * 1024 * 1024:
        return jsonify({'error': 'File too large'}), 400
    
    # Save the file
    file.save(file_path)
    
    # Process image/document (e.g., resize images, extract archives)
    if mime_type == 'image/jpeg' or mime_type == 'image/png':
        img = Image.open(file_path)
        img.thumbnail((100, 100))  # Resize to 100x100 pixels
        img.save(file_path)
    
    return jsonify({'message': 'File uploaded successfully'}), 201

if __name__ == '__main__':
    app.run(debug=True)